    print(_fmt("leader",         sr_sigs.get("leader_symbol")))
    print(_fmt("linkage_score",  sr_sigs.get("linkage_score")))
    print(_fmt("laggard_follow", _bool(sr_sigs.get("laggard_follow_signal"))))
    sr_r = sr_sigs.get("sector_rotation_reason", "")
