    try:
        from release.version_info import VERSION as _VI_VER, BASE_RELEASE as _VI_BASE
        _ver_display = _VI_VER
        _base_display = _VI_BASE
    except Exception:
        _ver_display = "1.0.1"
        _base_display = "1.0.0"
