    print(f"{'Base Release:':<35} {_base_display} Research Trading Cockpit Stable")
    print(f"{'Release:':<35} Research Trading Cockpit Stable")
    print(f"{'Stage:':<35} STABLE")
    print(f"{'Research Only:':<35} True")
