    from data.providers.data_gov_tw.allowlist_v143 import DataGovTwAllowlist
    al = DataGovTwAllowlist()
    entries = al.list_all()
    if keyword:
        kw = keyword.lower()
        entries = [e for e in entries if kw in (e.get("title") or "").lower() or kw in (e.get("dataset_id") or "").lower()]
    print("=" * 60)
